SELECT test_name, test_duration
FROM hardware_tests
WHERE tested_by = 'Bob Smith' AND test_status = 'completed';

SELECT observed_value
FROM metric_results
WHERE test_id = 1 AND test_iteration = 1;

SELECT AVG(observed_value) AS average_observed_value
FROM metric_results
WHERE metric_id = 0;

SELECT COUNT(test_id) AS total_completed_tests
FROM hardware_tests
WHERE test_status = 'completed';

SELECT COUNT(*) AS completed_test_count
FROM hardware_tests
WHERE test_status = 'completed';

SELECT metric_id, AVG(observed_value) AS average_observed_value
FROM metric_results
GROUP BY metric_id;

SELECT log_severity, COUNT(*) AS severity_count
FROM test_logs
GROUP BY log_severity;

SELECT hardware_version, COUNT(test_id) AS total_tests
FROM hardware_tests
GROUP BY hardware_version;
